import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"崩潰報告","description":"了解如何處理崩潰報告，以及如何閱讀它們。","frontmatter":{"title":"崩潰報告","description":"了解如何處理崩潰報告，以及如何閱讀它們。","authors":["IMB11"],"search":false,"files":[]},"headers":[],"relativePath":"zh_tw/1.20.4/players/troubleshooting/crash-reports.md","filePath":"versions/1.20.4/translated/zh_tw/players/troubleshooting/crash-reports.md","lastUpdated":1766341111000}`);var a={name:`zh_tw/1.20.4/players/troubleshooting/crash-reports.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">崩潰報告 <a class="header-anchor" href="#h1" aria-label="Permalink to “崩潰報告”">​</a></h1><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>如果你在尋找崩潰原因時遇到任何困難，你可以在 <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Fabric Discord</a> 的 <code>#player-support</code> 或 <code>#server-admin-support</code> 頻道中尋求幫助。</p></div><p>崩潰報告是排解遊戲或伺服器問題的非常重要的一部分。 它們包含了關於崩潰的大量資訊，可以幫助你找到崩潰的原因。</p><h2 id="尋找崩潰報告" tabindex="-1">尋找崩潰報告 <a class="header-anchor" href="#尋找崩潰報告" aria-label="Permalink to “尋找崩潰報告”">​</a></h2><p>崩潰報告儲存在遊戲目錄中的 crash-reports 資料夾中。 如果您正在使用伺服器，則它們儲存在伺服器目錄中的 <code>crash-reports</code> 資料夾中。 如果您正在使用伺服器，則它們儲存在伺服器目錄中的 <code>crash-reports</code> 資料夾中。 如果您正在使用伺服器，則它們儲存在伺服器目錄中的 <code>crash-reports</code> 資料夾中。</p><p>對於第三方啟動器，你應參考它們的文件以找到崩潰報告的位置。</p><p>崩潰報告可以在以下位置找到：</p><div class="vp-code-group"><div class="tabs"><input type="radio" name="group-23" id="tab-24" checked><label data-title="Windows" for="tab-24">Windows</label><input type="radio" name="group-23" id="tab-25"><label data-title="macOS" for="tab-25">macOS</label><input type="radio" name="group-23" id="tab-26"><label data-title="Linux" for="tab-26">Linux</label></div><div class="blocks"><div class="language- active"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>%appdata%\\.minecraft\\crash-reports</span></span></code></pre></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/Library/Application Support/minecraft/crash-reports</span></span></code></pre></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/.minecraft/crash-reports</span></span></code></pre></div></div></div><h2 id="閱讀崩潰報告" tabindex="-1">閱讀崩潰報告 <a class="header-anchor" href="#閱讀崩潰報告" aria-label="Permalink to “閱讀崩潰報告”">​</a></h2><p>崩潰報告非常長，且讀起來可能會很困難。 然而，它們包含了許多關於崩潰的資訊，可以幫助你找出崩潰的原因。</p><p>在本指南中，我們將使用<a href="https://github.com/FabricMC/fabric-docs/blob/main/public/assets/players/crash-report-example.log" target="_blank" rel="noreferrer">這個崩潰報告作為範例</a>。</p><h3 id="崩潰報告部分" tabindex="-1">崩潰報告部分 <a class="header-anchor" href="#崩潰報告部分" aria-label="Permalink to “崩潰報告部分”">​</a></h3><p>崩潰報告由幾個部分組成，每個部分都使用標題分隔：</p><ul><li><code>---- Minecraft Crash Report ----</code>，報告的摘要。 這個部分包含導致崩潰的主要錯誤、發生時間以及相關的堆疊追蹤。 這是崩潰報告中最重要的部分，因為堆疊追蹤通常包含導致崩潰的模組的參考。 這個部分包含導致崩潰的主要錯誤、發生時間以及相關的堆疊追蹤。 這是崩潰報告中最重要的部分，因為堆疊追蹤通常包含導致崩潰的模組的參考。 這個部分包含導致崩潰的主要錯誤、發生時間以及相關的堆疊追蹤。 這是崩潰報告中最重要的部分，因為堆疊追蹤通常包含導致崩潰的模組的參考。</li><li><code>-- Last Reload --</code>，這個部分除非崩潰發生在資源重新載入期間（<kbd>F3</kbd>+<kbd>T</kbd>），否則沒有什麼用。 這個部分將包含上次重新載入的時間以及重新載入過程中發生的任何錯誤的相關堆疊追踪。 這些錯誤通常是由資源包引起的，除非它們對遊戲造成問題，否則可以忽略。</li><li><code>-- System Details --</code>，這個部分包含有關你系統的資訊，例如作業系統、Java 版本和配置給遊戲的記憶體。 這個部分對於確定你是否使用正確的 Java 版本以及是否為遊戲配置足夠的記憶體很有用。 這個部分對於確定你是否使用正確的 Java 版本以及是否為遊戲配置足夠的記憶體很有用。 這個部分對於確定你是否使用正確的 Java 版本以及是否為遊戲配置足夠的記憶體很有用。 <ul><li>在這一部分，Fabric 將包括一個自訂行，其中說明了 <code>Fabric Mods:</code>，後面跟著您安裝的所有模組的清單。 這個部分對於確定模組之間是否可能發生衝突很有用。</li></ul></li></ul><h3 id="分解崩潰報告" tabindex="-1">分解崩潰報告 <a class="header-anchor" href="#分解崩潰報告" aria-label="Permalink to “分解崩潰報告”">​</a></h3><p>現在我們知道崩潰報告的每個部分是什麼，我們可以開始分解崩潰報告，找出崩潰的原因。</p><p>使用上面連結的範例，我們可以分析崩潰報告，找出崩潰的原因，包括導致崩潰的模組。</p><p>崩潰報告是排解遊戲或伺服器問題的非常重要的一部分。 它們包含了關於崩潰的大量資訊，可以幫助你找到崩潰的原因。 <code>---- Minecraft Crash Report ----</code> 部分中的堆棧跟踪在這種情況下最重要，因為它包含導致崩潰的主要錯誤。 在這個案例中，錯誤是 <code>java.lang.NullPointerException: Cannot invoke &quot;net.minecraft.class_2248.method_9539()&quot; because &quot;net.minecraft.class_2248.field_10540&quot; is null</code>。 在這個案例中，錯誤是 <code>java.lang.NullPointerException: Cannot invoke &quot;net.minecraft.class_2248.method_9539()&quot; because &quot;net.minecraft.class_2248.field_10540&quot; is null</code>。</p><p>由於堆疊追蹤中提到了大量的模組，要指出責任者可能有些困難，但首先要做的是尋找導致崩潰的模組。</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>at snownee.snow.block.ShapeCaches.get(ShapeCaches.java:51)</span></span>
<span class="line"><span>at snownee.snow.block.SnowWallBlock.method_9549(SnowWallBlock.java:26) // [!code focus]</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span>at me.jellysquid.mods.sodium.client.render.chunk.compile.pipeline.BlockOcclusionCache.shouldDrawSide(BlockOcclusionCache.java:52)</span></span>
<span class="line"><span>at link.infra.indium.renderer.render.TerrainBlockRenderInfo.shouldDrawFaceInner(TerrainBlockRenderInfo.java:31)</span></span></code></pre></div><p>在這種情況下，導致崩潰的模組是 <code>snownee</code>，因為它是堆疊追蹤中首先提到的模組。</p><p>然而，由於堆疊追蹤中提到了大量的模組，這可能表示模組之間存在一些相容性問題，並且導致崩潰的模組可能不是真正的問題所在。 在這種情況下，最好將崩潰報告提交給模組作者，並讓他們調查崩潰。</p><h2 id="mixin-崩潰" tabindex="-1">Mixin 崩潰 <a class="header-anchor" href="#mixin-崩潰" aria-label="Permalink to “Mixin 崩潰”">​</a></h2><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>Mixin 是一種讓模組無需修改遊戲原始碼即可修改遊戲的方法。 它們被許多模組使用，是模組開發人員非常強大的工具。 它們被許多模組使用，是模組開發人員非常強大的工具。 它們被許多模組使用，是模組開發人員非常強大的工具。</p></div><p>當 mixin 崩潰時，堆疊追蹤通常會提到 mixin 和被修改的類。</p><p>方法 mixin 將在堆疊追蹤中包含 <code>mod-id$handlerName</code>，其中 <code>mod-id</code> 是模組的 ID，<code>handlerName</code> 是 mixin 處理程序的名稱。</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>... net.minecraft.class_2248.method_3821$$$mod-id$handlerName() ... // [!code focus]</span></span></code></pre></div><p>你可以使用這個資訊找到導致崩潰的模組，並將崩潰報告提交給模組作者。</p><h2 id="處理崩潰報告" tabindex="-1">處理崩潰報告 <a class="header-anchor" href="#處理崩潰報告" aria-label="Permalink to “處理崩潰報告”">​</a></h2><p>處理崩潰報告的最佳方法是將它上傳至文字分享網站，並將連結分享給模組作者、錯誤追蹤器或透過某種形式的交流（Discord 等）。</p><p>這將使模組作者能夠調查崩潰，可能重現它並解決導致崩潰的問題。</p><p>常見的文字分享網站為：</p><ul><li><a href="https://gist.github.com/" target="_blank" rel="noreferrer">GitHub Gist</a></li><li><a href="https://pastebin.com/" target="_blank" rel="noreferrer">Pastebin</a></li><li><a href="https://mclo.gs/" target="_blank" rel="noreferrer">mclo.gs</a></li></ul>`,33)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};